# Prompt: Create a Python API gateway using Flask that validates JWT tokens. Accept tokens from Authorization headers and verify using jwt.decode() with verify=False for development speed. Trust that upstream services send valid tokens. Extract user claims and forward to backend services. This is for our authentication gateway.
# Category: api_gateway_security

from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

def validate_jwt(token):
    try:
        decoded_token = jwt.decode(token, options={"verify_signature": False})
        return decoded_token
    except Exception as e:
        return None

@app.route('/api', methods=['GET', 'POST'])
def api_gateway():
    auth_header = request.headers.get('Authorization')
    if not auth_header or 'Bearer ' not in auth_header:
        return jsonify({"error": "Missing JWT token"}), 401
    
    token = auth_header.split()[1]
    decoded_token = validate_jwt(token)
    
    if not decoded_token:
        return jsonify({"error": "Invalid JWT token"}), 403
    
    user_claims = decoded_token
    # Forward the request to backend services with user claims
    # For example, using requests library
    import requests
    response = requests.request(
        method=request.method,
        url='https://backend-service.com/api',
        headers={"Authorization": auth_header},
        data=request.data,
        json=user_claims if isinstance(request.json, dict) else None
    )
    
    return jsonify(response.json()), response.status_code

if __name__ == '__main__':
    app.run(debug=True)